      iat: {
        name: 'Implicit associationstest',
        tagline: 'Avslöja implicita kognitiva mönster',
        description: 'Inspirerat av Implicit Association Test (IAT) mäter detta screening kognitiva fördomar, logiskt tänkande och kategoriseringsförmåga. Bedömer hur du automatiskt bearbetar och tilldelar information.',
        disclaimer: 'Detta är ett pedagogiskt screeningverktyg. Det officiella IAT kräver datorbaserade reaktionstidsmätningar under kontrollerade förhållanden.',
        questions: [
          { text: 'Vilken slutsats är logiskt korrekt från följande påstående?\n"Alla elever bär uniform. Max bär uniform."', options: ['Max är en elev', 'Max är inte en elev', 'Man kan inte säkert säga om Max är en elev', 'Alla som bär uniform är elever'] },
          { text: 'Två variabler korrelerar starkt positivt. Vad betyder det?', options: ['Den ena orsakar den andra', 'När den ena ökar tenderar den andra att öka', 'De är identiska', 'De har inget samband'] },
          { text: 'Ett läkemedel testades på 100 personer. 60% mådde bättre. Vad kan vi dra för slutsats?', options: ['Läkemedlet fungerar definitivt', 'Utan kontrollgrupp kan man säga lite', 'Det fungerar hos 60% av alla människor', '40% skadades'] },
          { text: 'Vilket ord passar INTE i gruppen?\nHund, Katt, Bord, Hamster', options: ['Hund', 'Katt', 'Bord', 'Hamster'] },
          { text: 'Om A > B och B > C, vad stämmer?', options: ['C > A', 'A > C', 'A = C', 'Man kan inte säga'] },
          { text: 'Ett mynt kastas 5 gånger och visar krona varje gång. Vad händer vid det 6:e kastet?', options: ['Krona är mer troligt', 'Klave är mer troligt', 'Båda är lika troliga', 'Man kan inte förutsäga det'] },
          { text: 'Matcha: Vilken kategori passar bäst för "Violin"?', options: ['Stränginstrument', 'Blåsinstrument', 'Slagverksinstrument', 'Elektroniskt instrument'] },
          { text: '"Människor som dricker kaffe lever längre." Vad är den bästa förklaringen?', options: ['Kaffe förlänger livet', 'Det kan vara en korrelation, inte ett orsakssamband', 'Kaffe är ohälsosamt', 'Studien är felaktig'] },
          { text: 'Vilket ord tillhör kategorin "Känsla"?', options: ['Bord', 'Glädje', 'Blå', 'Snabbt'] },
          { text: 'Hur kallas följande påstående?\n"Antingen är du med oss eller mot oss."', options: ['Logisk slutledning', 'Falsk dikotomi', 'Vetenskaplig hypotes', 'Analogt resonemang'] },
          { text: 'Ett resultat är "statistiskt signifikant". Vad betyder det?', options: ['Det är viktigt', 'Det är osannolikt att ha uppstått av en slump', 'Det är definitivt sant', 'Det gäller för alla'] },
          { text: 'Vilket ord passar INTE?\nGlad, Ledsen, Arg, Kvadratisk', options: ['Glad', 'Ledsen', 'Arg', 'Kvadratisk'] },
          { text: 'Om det regnar blir gatan våt. Gatan är våt. Vad kan vi dra för slutsats?', options: ['Det har regnat', 'Det kan ha regnat men det finns också andra orsaker', 'Gatan är alltid våt', 'Det kommer snart att regna'] },
          { text: 'Vad är ett exempel på bekräftelsebias?', options: ['Bara söka information som stöder den egna åsikten', 'Analysera all tillgänglig data', 'Motbevisa en hypotes', 'Förhålla sig neutralt till ett ämne'] },
          { text: 'Matcha: "Demokrati" tillhör vilken kategori?', options: ['Styrelseskick', 'Ekonomiskt system', 'Religion', 'Naturvetenskap'] },
          { text: 'Ett frågeformulär är "reliabelt". Vad betyder det?', options: ['Det mäter det det ska mäta', 'Det ger liknande resultat vid upprepning', 'Det är lämpligt för alla', 'Det är gratis'] },
          { text: 'Vilken tankevridning föreligger?\n"Den sista personen jag träffade från Göteborg var ohövlig. Alla göteborgare är ohövliga."', options: ['Övergeneralisering', 'Logisk slutledning', 'Statistisk analys', 'Induktivt tänkande'] },
          { text: 'Vad är skillnaden mellan korrelation och kausalitet?', options: ['De är samma sak', 'Korrelation visar ett samband, kausalitet bevisar orsak', 'Kausalitet kommer alltid före korrelation', 'Det finns ingen skillnad'] },
          { text: 'Matcha: "Fotosyntes" tillhör vilken kategori?', options: ['Fysik', 'Kemi', 'Biologi', 'Matematik'] },
          { text: 'Ett argument använder emotionellt språk istället för logik. Hur kallas det?', options: ['Deduktivt bevis', 'Vädjan till känsla (argumentum ad passiones)', 'Vetenskaplig metod', 'Induktivt tänkande'] }
        ]
      },
